const item = $json;
const config = item.action_config || {};
let msg = config.message || 'Hola, tenemos un mensaje para ti.';
msg = msg.replace(/\{\{nombre\}\}/g, item.customer_name || 'cliente');
msg = msg.replace(/\{\{servicio\}\}/g, item.service_name || '');
if (item.start_time) {
  const d = new Date(item.start_time);
  msg = msg.replace(/\{\{fecha\}\}/g, d.toLocaleDateString('es-MX'));
}
return [{ json: { ...item, resolvedMessage: msg } }];
